const targets = [
  path.resolve(__dirname, '../resources/i18n/en.json'),
  path.resolve(__dirname, '../../fanotes-site/public/i18n/en.json'),
]

for (const target of targets) {
  const catalog = JSON.parse(fs.readFileSync(target, 'utf8'))
  const merged = Object.fromEntries(Object.entries({ ...catalog, ...overrides })
    .filter(([source, translation]) => !/obsidian/iu.test(source) && !/obsidian/iu.test(String(translation)))
    .sort(([left], [right]) => left.localeCompare(right, 'de')))
  fs.writeFileSync(target, `${JSON.stringify(merged, null, 2)}\n`)
  console.log(`Applied ${Object.keys(overrides).length} reviewed translations to ${target}`)
}
